// ❌ BAD - loads all pages into memory before returning anything
IEnumerable<Product> LoadAllProducts() {
    var all = new List<Product>();
    for (int page = 1; ; page++) {
        var batch = _api.GetProducts(page);
        if (!batch.Any()) break;
        all.AddRange(batch); // holds everything in RAM
    }
    return all;
}

// ✅ GOOD - yields each batch lazily; caller processes and discards it
IEnumerable<Product> StreamProducts() {
    for (int page = 1; ; page++) {
        var batch = _api.GetProducts(page);
        if (!batch.Any()) yield break;
        foreach (var product in batch) yield return product;
    }
}

// ❌ BAD - class has reference equality; two identical DTOs are not equal
public class OrderDto { public int Id { get; set; } public decimal Total { get; set; } }
var a = new OrderDto { Id = 1, Total = 99m };
var b = new OrderDto { Id = 1, Total = 99m };
Console.WriteLine(a == b); // False - different references

// ✅ GOOD - record has value equality and with-expression
public record OrderSummary(int Id, string Customer, decimal Total);
var order = new OrderSummary(1, "Alice", 99.99m);
var updated = order with { Total = 149.99m };
Console.WriteLine(order == updated);                          // False
Console.WriteLine(order == new OrderSummary(1, "Alice", 99.99m)); // True

// ❌ BAD - old Tuple is a class with Item1/Item2, no names, heap allocation
Tuple<string, decimal> GetPrice() => Tuple.Create("GBP", 9.99m);
var price = GetPrice();
Console.WriteLine(price.Item2); // unclear what Item2 means

// ✅ GOOD - ValueTuple: struct, named, deconstructable
(string Currency, decimal Amount) GetPrice() => ("GBP", 9.99m);
var (currency, amount) = GetPrice();
Console.WriteLine($"{amount} {currency}"); // clear and readable

// ❌ BAD - out variable not assigned on every path; compiler error
bool TryGetDiscount(int customerId, out decimal discount) {
    if (customerId > 0) { discount = 0.1m; return true; }
    return false; // compiler error: discount not assigned
}

// ✅ GOOD - out assigned on all paths; ref modifies caller's variable
bool TryGetDiscount(int customerId, out decimal discount) {
    if (customerId > 0) { discount = 0.1m; return true; }
    discount = 0; return false; // must assign
}
void ApplySurcharge(ref decimal total) => total *= 1.2m;
decimal price = 100m;
ApplySurcharge(ref price); // price is now 120

// ❌ BAD - no NRT; null slips through silently
public string GetEmail(int userId) {
    return _db.Users.Find(userId).Email; // crashes if user not found
}

// ✅ GOOD - NRT enabled; compiler warns at risky dereferences
public string? GetEmail(int userId) {
    var user = _db.Users.Find(userId); // User?
    return user?.Email; // safe: returns null if user is null
}
// Caller forced to check:
var email = GetEmail(1);
if (email is not null) SendConfirmation(email);
